public static <T extends KLine> DistanceService<T> getDistanceService(String name, Class<T> type) {
    return AppContextHolder.getContext().getBeansOfType(DistanceService.class).values()
                .stream()
                .filter(distanceService -> type.isInstance(distanceService.getTargetType()))
                .filter(distanceService -> Objects.equals(distanceService.getName(), name))
                .findAny()
                .map(distanceService -> {
                    // 抑制未检查的转换警告
